export const Section = /*#__PURE__*/ createBranchComponent(
  'section',
  <T extends any>(
    props: SectionProps<T>,
    ref: ForwardedRef<HTMLElement>,
    section: Node<T>
  ): JSX.Element => {
    let {name, render} = useContext(SectionContext)!;
    if (process.env.NODE_ENV !== 'production') {
      console.warn(`<Section> is deprecated. Please use <${name}> instead.`);
    }
    return render(props, ref, section, 'react-aria-Section');
  }
);

if (node.type === 'item' && node.firstChildKey != null && this.expandedKeys.has(node.key)) {
  let child = this.getItem(node.firstChildKey) as CollectionNode<T> | null;
  while (child) {
    if (child.type === 'item') {
      return child.key;
    }

    child = child.nextKey != null ? (this.getItem(child.nextKey) as CollectionNode<T>) : null;
  }
}

if (node.prevKey != null) {
  node = this.getItem(node.prevKey) as CollectionNode<T>;

  // Traverse to the deepest expanded child.
  while (
    node &&
    (node.type !== 'item' || this.expandedKeys.has(node.key)) &&
    node.lastChildKey != null
  ) {
    node = this.getItem(node.lastChildKey) as CollectionNode<T>;
  }

  k = node?.key ?? null;
}

for (let key of keys) {
  if (!excludeSet.has(key)) {
    let currentKey: Key | null = key;
    while (currentKey != null) {
      let item = collection.getItem(currentKey) as CollectionNode<T>;
      if (item?.type === 'section') {
        collection.keyMap.set(currentKey, item.clone());
        break;
      } else {
        currentKey = item?.parentKey ?? null;
      }
    }
  }
}

if (ctx && typeof ctx === 'object' && 'slots' in ctx && ctx.slots) {
  let slotKey = slot || DEFAULT_SLOT;
  if (!ctx.slots[slotKey]) {
    let availableSlots = new Intl.ListFormat().format(Object.keys(ctx.slots).map(p => `"${p}"`));
    let errorMessage = slot ? `Invalid slot "${slot}".` : 'A slot prop is required.';

    throw new Error(`${errorMessage} Valid slot names are ${availableSlots}.`);
  }
  return ctx.slots[slotKey];
}

let {focusWithinProps} = useFocusWithin({
  ...props,
  onFocusWithin(e) {
    valueOnFocus.current = state.value;
    props.onFocus?.(e);
  },
  onBlurWithin: e => {
    state.confirmPlaceholder();
    if (state.value !== valueOnFocus.current) {
      state.commitValidation();
    }
    props.onBlur?.(e);
  },
  onFocusWithinChange: props.onFocusChange
});

useLayoutEffect(() => {
    return () => {
      // Scope may have been re-parented.
      let parentScope = focusScopeTree.getTreeNode(scopeRef)?.parent?.scopeRef ?? null;

      if (
        (scopeRef === activeScope || isAncestorScope(scopeRef, activeScope)) &&
        (!parentScope || focusScopeTree.getTreeNode(parentScope))
      ) {
        activeScope = parentScope;
      }
      focusScopeTree.removeTreeNode(scopeRef);
    };
  }, [scopeRef]);

if (
  shouldSelectOnPressUp &&
  gridCellProps.tabIndex != null &&
  gridCellProps.onPointerDown == null
) {
  gridCellProps.onPointerDown = e => {
    let el = e.currentTarget;
    let tabindex = el.getAttribute('tabindex');
    el.removeAttribute('tabindex');
    requestAnimationFrame(() => {
      if (tabindex != null) {
        el.setAttribute('tabindex', tabindex);
      }
    });
  };
}

let end = useCallback(
  (originalEvent: EventBase, pointerType: PointerType) => {
    restoreTextSelection();
    if (state.current.didMove) {
      onMoveEnd?.({
        type: 'moveend',
        pointerType,
        shiftKey: originalEvent.shiftKey,
        metaKey: originalEvent.metaKey,
        ctrlKey: originalEvent.ctrlKey,
        altKey: originalEvent.altKey
      });
    }
  },
  [onMoveEnd, state]
);

return (
  (key === 'Enter' || key === ' ' || key === 'Spacebar' || code === 'Space') &&
  !(
    (element instanceof getOwnerWindow(element).HTMLInputElement &&
      !isValidInputKey(element, key)) ||
    element instanceof getOwnerWindow(element).HTMLTextAreaElement ||
    element.isContentEditable
  ) &&
  // Links should only trigger with Enter key
  !((role === 'link' || (!role && isHTMLAnchorLink(element))) && key !== 'Enter')
);

let onInteractOutsideStart = (e: PointerEvent) => {
  const topMostOverlay = visibleOverlays[visibleOverlays.length - 1];
  lastVisibleOverlay.current = topMostOverlay;
  if (
    !shouldCloseOnInteractOutside ||
    shouldCloseOnInteractOutside(getEventTarget(e) as Element)
  ) {
    if (topMostOverlay === ref) {
      e.stopPropagation();
    }
  }
};

if (shouldUseVirtualFocus) {
  itemPressProps = mergeProps(itemPressProps, {
    onPressStart(e) {
      if (e.pointerType !== 'touch') {
        manager.setFocused(true);
        manager.setFocusedKey(key);
      }
    },
    onPress(e) {
      if (e.pointerType === 'touch') {
        manager.setFocused(true);
        manager.setFocusedKey(key);
      }
    }
  });
}

for (const prop in props) {
  if (
    Object.prototype.hasOwnProperty.call(props, prop) &&
    (DOMPropNames.has(prop) ||
      (labelable && labelablePropNames.has(prop)) ||
      (isLink && linkPropNames.has(prop)) ||
      (global && globalAttrs.has(prop)) ||
      (events &&
        (globalEvents.has(prop) ||
          (prop.endsWith('Capture') && globalEvents.has(prop.slice(0, -7))))) ||
      propNames?.has(prop) ||
      propRe.test(prop))
  ) {
    filteredProps[prop] = props[prop];
  }
}

let event =
    isWebKit() && isMac() && !isIPad() && process.env.NODE_ENV !== 'test'
      ? // @ts-ignore - keyIdentifier is a non-standard property, but it's what webkit expects
        new KeyboardEvent('keydown', {keyIdentifier: 'Enter', metaKey, ctrlKey, altKey, shiftKey})
      : new MouseEvent('click', {
          metaKey,
          ctrlKey,
          altKey,
          shiftKey,
          detail: 1,
          bubbles: true,
          cancelable: true
        });

if (shouldScrollBlock && block === 'start') {
  y += scrollAreaTop - scrollPortTop;
} else if (shouldScrollBlock && block === 'center') {
  y += (scrollAreaTop + scrollAreaBottom) / 2 - (scrollPortTop + scrollPortBottom) / 2;
} else if (shouldScrollBlock && block === 'end') {
  y += scrollAreaBottom - scrollPortBottom;
} else if (shouldScrollBlock && block === 'nearest') {
  let start = scrollAreaTop - scrollPortTop;
  let end = scrollAreaBottom - scrollPortBottom;
  y += Math.abs(start) <= Math.abs(end) ? start : end;
}

if (shouldScrollInline && inline === 'start') {
  x += scrollAreaLeft - scrollPortLeft;
} else if (shouldScrollInline && inline === 'center') {
  x += (scrollAreaLeft + scrollAreaRight) / 2 - (scrollPortLeft + scrollPortRight) / 2;
} else if (shouldScrollInline && inline === 'end') {
  x += scrollAreaRight - scrollPortRight;
} else if (shouldScrollInline && inline === 'nearest') {
  let start = scrollAreaLeft - scrollPortLeft;
  let end = scrollAreaRight - scrollPortRight;
  x += Math.abs(start) <= Math.abs(end) ? start : end;
}

let isUnavailable = useMemo(() => {
    if (!calendarDateValue) {
      return false;
    }

    if (Array.isArray(calendarDateValue)) {
      return calendarDateValue.some(
        date => isDateUnavailable?.(date) || isInvalid(date, minValue, maxValue)
      );
    }

    return (
      isDateUnavailable?.(calendarDateValue) || isInvalid(calendarDateValue, minValue, maxValue)
    );
  }, [calendarDateValue, isDateUnavailable, minValue, maxValue]);

switch (format) {
  case 'css':
    return this.toHSL().toString('css');
  case 'hex':
    return this.toRGB().toString('hex');
  case 'hexa':
    return this.toRGB().toString('hexa');
  case 'hsb':
    return `hsb(${this.hue}, ${toFixedNumber(this.saturation, 2)}%, ${toFixedNumber(this.brightness, 2)}%)`;
  case 'hsba':
    return `hsba(${this.hue}, ${toFixedNumber(this.saturation, 2)}%, ${toFixedNumber(this.brightness, 2)}%, ${this.alpha})`;
  default:
    return this.toFormat(format).toString(format);
}

if (this.orientation === 'horizontal') {
  rect.height = this.virtualizer!.contentSize.height - this.padding - y;
  rect.width = node.props.isLoading
    ? (this.loaderSize ?? this.rowSize ?? this.estimatedRowSize ?? DEFAULT_HEIGHT)
    : 0;
} else {
  rect.width = this.virtualizer!.contentSize.width - this.padding - x;
  rect.height = node.props.isLoading
    ? (this.loaderSize ?? this.rowSize ?? this.estimatedRowSize ?? DEFAULT_HEIGHT)
    : 0;
}

return (
  newOptions.maxColumns !== oldOptions.maxColumns ||
  newOptions.dropIndicatorThickness !== oldOptions.dropIndicatorThickness ||
  !(newOptions.minItemSize || DEFAULT_OPTIONS.minItemSize).equals(
    oldOptions.minItemSize || DEFAULT_OPTIONS.minItemSize
  ) ||
  !(newOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize).equals(
    oldOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize
  ) ||
  !(newOptions.minSpace || DEFAULT_OPTIONS.minSpace).equals(
    oldOptions.minSpace || DEFAULT_OPTIONS.minSpace
  ) ||
  newOptions.maxHorizontalSpace !== oldOptions.maxHorizontalSpace ||
  newOptions.loaderHeight !== oldOptions.loaderHeight
);

const onLayoutChange = useCallback<NonNullable<OnGroupLayoutChange>>(
  (layout: Layout) => {
    clearPendingTimeout();

    if (debounceSaveMs === 0) {
      onLayoutChanged(layout);
    } else {
      timeoutRef.current = setTimeout(() => {
        onLayoutChanged(layout);
      }, debounceSaveMs);
    }
  },
  [clearPendingTimeout, debounceSaveMs, onLayoutChanged]
);

const TreeViewImpl = <T extends TreeNode>(props: TreeViewRootProviderProps<T>, ref: React.Ref<HTMLDivElement>) => {
  const [renderStrategyProps, treeViewProps] = splitRenderStrategyProps(props)
  const [{ value: treeView }, localProps] = createSplitProps<RootProviderProps<T>>()(treeViewProps, ['value'])
  const mergedProps = mergeProps(treeView.getRootProps(), localProps)

  return (
    <TreeViewProvider value={treeView}>
      <RenderStrategyPropsProvider value={renderStrategyProps}>
        <ark.div {...mergedProps} ref={ref} />
      </RenderStrategyPropsProvider>
    </TreeViewProvider>
  )
}

children.forEach((child) => {
  if (
    child.type === "JSXElement" &&
    child.openingElement?.name?.name === "BreadcrumbItem"
  ) {
    items.push(child)
  } else if (child.type !== "JSXText" || child.value.trim() !== "") {
    // Preserve non-empty text and other elements
    if (child.type !== "JSXText" || child.value.trim()) {
      newChildren.push(child)
    }
  }
})

root
    .find(j.ImportDeclaration, { source: { value: "@chakra-ui/react" } })
    .forEach((path) => {
      path.node.specifiers?.forEach((spec) => {
        if (
          spec.type === "ImportSpecifier" &&
          (spec.imported.name === "Link" ||
            spec.imported.name === "LinkOverlay") &&
          spec.local?.name
        ) {
          chakraLinkNames.push(spec.local.name as string)
        }
      })
    })

root.find(j.JSXOpeningElement).forEach((path) => {
  const baseName = getJsxBaseName(path.node.name)
  const isChakra = chakraLocalNames.has(baseName)
  const resolvesToMenu =
    baseName === "Menu" ||
    (componentAliases.has(baseName) &&
      componentAliases.get(baseName) === "Menu")
  if (!isChakra || !resolvesToMenu) return
  path.node.name = j.jsxMemberExpression(
    j.jsxIdentifier("Menu"),
    j.jsxIdentifier("Root"),
  )
})

root
    .find(j.JSXClosingElement, {
      name: { type: "JSXIdentifier", name: "MenuItem" },
    })
    .forEach((path) => {
      const hasChakraMenu =
        chakraLocalNames.has("Menu") ||
        Array.from(componentAliases.values()).includes("Menu")
      if (!hasChakraMenu) return
      path.node.name = j.jsxMemberExpression(
        j.jsxIdentifier("Menu"),
        j.jsxIdentifier("Item"),
      )
    })

root.find(j.ObjectPattern).forEach((path) => {
  path.node.properties.forEach((prop) => {
    if (
      prop.type === "Property" &&
      prop.key.type === "Identifier" &&
      prop.key.name === "casing" &&
      prop.value.type === "Identifier" &&
      prop.value.name === "casing" &&
      prop.shorthand
    ) {
      prop.key.name = "textTransform"
      prop.shorthand = false
    }
  })
})
